1	import { useState } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import { supabase } from "@/integrations/supabase/client";
4	import type { Asset } from "@/types/assets";
5	import { getPathDisplayModes, getUserSyncRoot, setUserSyncRoot, type NasConfig } from "@/lib/path-utils";
6	import { getOpenFolderUri, buildOpenFolderUri, getPreferredPathMode, setPreferredPathMode, type PathMode } from "@/lib/open-folder";
7	import { formatFilename } from "@/lib/format-filename";
8	import { format } from "date-fns";
9	import { toast } from "sonner";
10	import { Badge } from "@/components/ui/badge";
11	import { Button } from "@/components/ui/button";
12	import { Input } from "@/components/ui/input";
13	import { Label } from "@/components/ui/label";
14	import { ScrollArea } from "@/components/ui/scroll-area";
15	import { Separator } from "@/components/ui/separator";
16	import {
17	  Select,
18	  SelectContent,
19	  SelectItem,
20	  SelectTrigger,
21	  SelectValue,
22	} from "@/components/ui/select";
23	import {
24	  Popover,
25	  PopoverContent,
26	  PopoverTrigger,
27	} from "@/components/ui/popover";
28	import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
29	import {
30	  X,
31	  Copy,
32	  Check,
33	  ImageOff,
34	  Sparkles,
35	  Clock,
36	  HardDrive,
37	  Tag,
38	  FileText,
39	  History,
40	  Loader2,
41	  FolderOpen,
42	  Settings2,
43	} from "lucide-react";
44	import { Constants } from "@/integrations/supabase/types";
45	import { cn } from "@/lib/utils";
46	import CheckoutBar from "@/components/library/CheckoutBar";
47	
48	interface AssetDetailPanelProps {
49	  asset: Asset;
50	  onClose: () => void;
51	}
52	
53	function CopyIconButton({ value }: { value: string }) {
54	  const [copied, setCopied] = useState(false);
55	  const copy = async (e: React.MouseEvent) => {
56	    e.stopPropagation();
57	    await navigator.clipboard.writeText(value);
58	    setCopied(true);
59	    setTimeout(() => setCopied(false), 1500);
60	  };
61	  return (
62	    <Button variant="ghost" size="icon" className="h-6 w-6 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" onClick={copy}>
63	      {copied ? <Check className="h-3 w-3 text-[hsl(var(--success))]" /> : <Copy className="h-3 w-3" />}
64	    </Button>
65	  );
66	}
67	
68	function CopyButton({ value, label, folderUri }: { value: string; label: string; folderUri?: string }) {
69	  const [copied, setCopied] = useState(false);
70	
71	  const copy = async () => {
72	    await navigator.clipboard.writeText(value);
73	    setCopied(true);
74	    setTimeout(() => setCopied(false), 1500);
75	  };
76	
77	  return (
78	    <div className="group flex items-start gap-2">
79	      <div className="flex-1 min-w-0">
80	        <span className="text-[10px] uppercase text-muted-foreground tracking-wider">{label}</span>
81	        {folderUri ? (
82	          <a
83	            href={folderUri}
84	            className="block text-xs font-mono break-all text-foreground/80 mt-0.5 hover:text-foreground hover:underline cursor-pointer"
85	            title="Click to open containing folder"
86	          >
87	            {value}
88	          </a>
89	        ) : (
90	          <p className="text-xs font-mono break-all text-foreground/80 mt-0.5">{value}</p>
91	        )}
92	      </div>
93	      <Button
94	        variant="ghost"
95	        size="icon"
96	        className="h-6 w-6 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity"
97	        onClick={copy}
98	      >
99	        {copied ? <Check className="h-3 w-3 text-success" /> : <Copy className="h-3 w-3" />}
100	      </Button>
101	    </div>
102	  );
103	}
104	
105	function MetaRow({ label, value }: { label: string; value: React.ReactNode }) {
106	  return (
107	    <div className="flex justify-between items-baseline gap-2">
108	      <span className="text-xs text-muted-foreground shrink-0">{label}</span>
109	      <span className="text-xs text-foreground text-right truncate">{value ?? "—"}</span>
110	    </div>
111	  );
112	}
113	
114	function formatSize(bytes: number | null): string {
115	  if (!bytes) return "—";
116	  if (bytes < 1024) return `${bytes} B`;
117	  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
118	  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
119	}
120	
121	export default function AssetDetailPanel({ asset, onClose }: AssetDetailPanelProps) {
122	  const queryClient = useQueryClient();
123	  const [editingTags, setEditingTags] = useState(false);
124	  const [tagInput, setTagInput] = useState("");
125	  const [aiTagging, setAiTagging] = useState(false);
126	  const [pathMode, setPathModeState] = useState<PathMode>(getPreferredPathMode);
127	  const [syncRoot, setSyncRootState] = useState<string>(getUserSyncRoot() ?? "");
128	
129	  // Fetch NAS config for path display
130	  const { data: nasConfig } = useQuery({
131	    queryKey: ["nas-config"],
132	    queryFn: async () => {
133	      const { data, error } = await supabase
134	        .from("admin_config")
135	        .select("key, value")
136	        .in("key", ["NAS_HOST", "NAS_IP", "NAS_SHARE"]);
137	      if (error) throw error;
138	      const map: Record<string, string> = {};
139	      for (const row of data ?? []) {
140	        map[row.key] = typeof row.value === "string" ? row.value : String(row.value);
141	      }
142	      return {
143	        NAS_HOST: map.NAS_HOST ?? "nas",
144	        NAS_IP: map.NAS_IP ?? "0.0.0.0",
145	        NAS_SHARE: map.NAS_SHARE ?? "share",
146	      } as NasConfig;
147	    },
148	    staleTime: 5 * 60 * 1000,
149	  });
150	
151	  // Fetch path history
152	  const { data: pathHistory } = useQuery({
153	    queryKey: ["path-history", asset.id],
154	    queryFn: async () => {
155	      const { data, error } = await supabase
156	        .from("asset_path_history")
157	        .select("*")
158	        .eq("asset_id", asset.id)
159	        .order("detected_at", { ascending: false })
160	        .limit(10);
161	      if (error) throw error;
162	      return data ?? [];
163	    },
164	  });
165	
166	  // Fetch related licensor/property names
167	  const { data: licensorName } = useQuery({
168	    queryKey: ["licensor-name", asset.licensor_id],
169	    queryFn: async () => {
170	      if (!asset.licensor_id) return null;
171	      const { data } = await supabase.from("licensors").select("name").eq("id", asset.licensor_id).single();
172	      return data?.name ?? null;
173	    },
174	    enabled: !!asset.licensor_id,
175	  });
176	
177	  const { data: propertyName } = useQuery({
178	    queryKey: ["property-name", asset.property_id],
179	    queryFn: async () => {
180	      if (!asset.property_id) return null;
181	      const { data } = await supabase.from("properties").select("name").eq("id", asset.property_id).single();
182	      return data?.name ?? null;
183	    },
184	    enabled: !!asset.property_id,
185	  });
186	
187	  // Update mutation
188	  const updateAsset = useMutation({
189	    mutationFn: async (updates: Record<string, unknown>) => {
190	      const { data, error } = await supabase.from("assets").update(updates).eq("id", asset.id).select("id");
191	      if (error) throw error;
192	      if (!data || data.length === 0) throw new Error("Update was blocked — you may not have permission to edit this asset");
193	    },
194	    onSuccess: () => {
195	      queryClient.invalidateQueries({ queryKey: ["assets"] });
196	      toast("Asset updated");
197	    },
198	    onError: (e) => {
199	      toast.error("Update failed", { description: e.message });
200	    },
201	  });
202	
203	  // AI Tag — routes through the Railway worker via persistent operation
204	  const handleAiTag = async () => {
205	    setAiTagging(true);
206	    try {
207	      const opKey = `ai-tag-single-${asset.id}`;
208	      const now = new Date().toISOString();
209	      const { error } = await supabase.rpc("update_bulk_operation", {
210	        p_op_key: opKey,
211	        p_op_state: {
212	          status: "running",
213	          cursor: 0,
214	          params: { type: "bulk-ai-tag-all", asset_ids: [asset.id], total: 1 },
215	          started_at: now,
216	          updated_at: now,
217	          progress: { tagged: 0, skipped: 0, failed: 0, total: 1 },
218	        },
219	      });
220	      if (error) throw error;
221	
222	      // Poll for completion (worker picks it up within ~5s)
223	      const maxWaitMs = 90_000;
224	      const pollMs = 2_000;
225	      const start = Date.now();
226	      while (Date.now() - start < maxWaitMs) {
227	        await new Promise((r) => setTimeout(r, pollMs));
228	        const { data: configRow } = await supabase
229	          .from("admin_config")
230	          .select("value")
231	          .eq("key", "BULK_OPERATIONS")
232	          .maybeSingle();
233	        const ops = configRow?.value as Record<string, any> | undefined;
234	        const op = ops?.[opKey];
235	        if (!op || op.status === "completed") {
236	          // Clean up the single-use operation key
237	          try { await supabase.rpc("update_bulk_operation", {
238	            p_op_key: opKey,
239	            p_op_state: { status: "idle" },
240	          }); } catch { /* best-effort cleanup */ }
241	          queryClient.invalidateQueries({ queryKey: ["assets"] });
242	          queryClient.invalidateQueries({ queryKey: ["asset-tags", asset.id] });
243	          toast("AI tagging complete");
244	          return;
245	        }
246	        if (op.status === "failed" || op.status === "interrupted") {
247	          throw new Error(op.error || "AI tagging failed");
248	        }
249	      }
250	      toast("AI tagging is still running — check back shortly");
251	    } catch (e: any) {
252	      toast.error("AI tagging failed", { description: e.message });
253	    } finally {
254	      setAiTagging(false);
255	    }
256	  };
257	
258	  // Fetch tag provenance
259	  const { data: assetTags } = useQuery({
260	    queryKey: ["asset-tags", asset.id],
261	    queryFn: async () => {
262	      const { data, error } = await supabase
263	        .from("asset_tags")
264	        .select("id, tag, source, created_by")
265	        .eq("asset_id", asset.id)
266	        .order("tag");
267	      if (error) throw error;
268	      return data ?? [];
269	    },
270	  });
271	
272	  const tagSourceMap = new Map<string, string>();
273	  for (const t of assetTags ?? []) {
274	    tagSourceMap.set(t.tag, t.source);
275	  }
276	
277	  // Tags
278	  const addTag = async () => {
279	    const tag = tagInput.trim().toLowerCase();
280	    if (!tag || asset.tags.includes(tag)) return;
281	    const { data, error } = await supabase.from("asset_tags").upsert(
282	      { asset_id: asset.id, tag, source: "manual" },
283	      { onConflict: "asset_id,tag" }
284	    ).select("id");
285	    if (error) {
286	      toast.error("Failed to add tag", { description: error.message });
287	      return;
288	    }
289	    if (!data || data.length === 0) {
290	      toast.error("Failed to add tag", { description: "Write was blocked — you may not have permission" });
291	      return;
292	    }
293	    queryClient.invalidateQueries({ queryKey: ["assets"] });
294	    queryClient.invalidateQueries({ queryKey: ["asset-tags", asset.id] });
295	    setTagInput("");
296	  };
297	
298	  const removeTag = async (tag: string) => {
299	    const { data, error } = await supabase
300	      .from("asset_tags")
301	      .delete()
302	      .eq("asset_id", asset.id)
303	      .eq("tag", tag)
304	      .select("id");
305	    if (error) {
306	      toast.error("Failed to remove tag", { description: error.message });
307	      return;
308	    }
309	    if (!data || data.length === 0) {
310	      toast.error("Failed to remove tag", { description: "Write was blocked — you may not have permission" });
311	      return;
312	    }
313	    queryClient.invalidateQueries({ queryKey: ["assets"] });
314	    queryClient.invalidateQueries({ queryKey: ["asset-tags", asset.id] });
315	  };
316	
317	  const paths = nasConfig ? getPathDisplayModes(asset.relative_path, nasConfig, getUserSyncRoot()) : null;
318	
319	  return (
320	    <TooltipProvider>
321	    <div className="flex h-full w-[384px] flex-col border-l border-border bg-surface-overlay animate-in slide-in-from-right duration-200">
322	      {/* Header */}
323	      <div className="group flex items-center gap-2 px-4 py-3 border-b border-border">
324	        <h3 className="text-sm font-medium truncate min-w-0 flex-1" title={asset.filename}>{formatFilename(asset.filename, 20)}</h3>
325	        <CopyIconButton value={asset.filename} />
326	        <CheckoutBar assetId={asset.id} />
327	        <Tooltip>
328	          <TooltipTrigger asChild>
329	            <Button
330	              variant="ghost"
331	              size="icon"
332	              className="h-7 w-7 shrink-0"
333	              onClick={handleAiTag}
334	              disabled={aiTagging || !asset.thumbnail_url}
335	            >
336	              {aiTagging ? <Loader2 className="h-4 w-4 animate-spin" /> : <Sparkles className="h-4 w-4" />}
337	            </Button>
338	          </TooltipTrigger>
339	          <TooltipContent side="bottom">
340	            {aiTagging ? "Re-tagging…" : !asset.thumbnail_url ? "No thumbnail — cannot re-tag" : "Re-tag with AI"}
341	          </TooltipContent>
342	        </Tooltip>
343	        <Button variant="ghost" size="icon" className="h-7 w-7 shrink-0" onClick={onClose}>
344	          <X className="h-4 w-4" />
345	        </Button>
346	      </div>
347	
348	      <ScrollArea className="flex-1">
349	        <div className="p-4 space-y-5">
350	          {/* Thumbnail */}
351	          <div className="aspect-[4/3] w-full rounded-lg bg-muted/30 overflow-hidden">
352	            {asset.thumbnail_url ? (
353	              <img src={asset.thumbnail_url} alt={asset.filename} className="h-full w-full object-contain" />
354	            ) : (
355	              <div className="flex h-full items-center justify-center">
356	                <ImageOff className="h-12 w-12 text-muted-foreground/20" />
357	              </div>
358	            )}
359	          </div>
360	
361	          <Separator />
362	
363	          {/* File info */}
364	          <section className="space-y-2">
365	            <h4 className="flex items-center gap-1.5 text-xs font-medium uppercase tracking-wider text-muted-foreground">
366	              <FileText className="h-3.5 w-3.5" /> File Info
367	            </h4>
368	            <div className="space-y-1.5">
369	              <MetaRow label="Type" value={<Badge variant="secondary" className="text-[10px] uppercase">{asset.file_type}</Badge>} />
370	              <MetaRow label="Size" value={formatSize(asset.file_size)} />
371	              <MetaRow label="Dimensions" value={asset.width && asset.height ? `${asset.width} × ${asset.height}` : "—"} />
372	              <MetaRow label="Artboards" value={asset.artboards ?? 1} />
373	              <MetaRow label="Status" value={<span className="capitalize">{asset.status}</span>} />
374	              <MetaRow
375	                label="Workflow"
376	                value={
377	                  <Select
378	                    value={asset.workflow_status ?? "other"}
379	                    onValueChange={(v) => updateAsset.mutate({ workflow_status: v })}
380	                  >
381	                    <SelectTrigger className="h-6 w-auto text-xs border-0 bg-transparent p-0">
382	                      <SelectValue />
383	                    </SelectTrigger>
384	                    <SelectContent>
385	                      {Constants.public.Enums.workflow_status.map((ws) => (
386	                        <SelectItem key={ws} value={ws} className="capitalize text-xs">
387	                          {ws.replace(/_/g, " ")}
388	                        </SelectItem>
389	                      ))}
390	                    </SelectContent>
391	                  </Select>
392	                }
393	              />
394	              <MetaRow label="Licensed" value={asset.is_licensed ? "Yes" : "No"} />
395	              <MetaRow label="Licensor" value={licensorName ?? "—"} />
396	              <MetaRow label="Property" value={propertyName ?? "—"} />
397	              {(asset as any).stage && <MetaRow label="Stage" value={(asset as any).stage} />}
398	              {(asset as any).customer && <MetaRow label="Customer" value={(asset as any).customer} />}
399	              {(asset as any).program && <MetaRow label="Program" value={(asset as any).program} />}
400	              {(asset as any).designer_name && <MetaRow label="Designer" value={(asset as any).designer_name} />}
401	              {(asset as any).technical_designer_name && <MetaRow label="Tech Designer" value={(asset as any).technical_designer_name} />}
402	              {(asset as any).freelancer_name && <MetaRow label="Freelancer" value={(asset as any).freelancer_name} />}
403	            </div>
404	          </section>
405	
406	          <Separator />
407	
408	          {/* Paths */}
409	          <section className="space-y-2.5">
410	            <h4 className="flex items-center gap-1.5 text-xs font-medium uppercase tracking-wider text-muted-foreground">
411	              <HardDrive className="h-3.5 w-3.5" /> Paths
412	            </h4>
413	            {nasConfig && (
414	              <div className="flex gap-1.5">
415	                <Button
416	                  variant="outline"
417	                  size="sm"
418	                  className="gap-1.5 text-xs h-7 flex-1"
419	                  asChild
420	                >
421	                  <a
422	                    href={getOpenFolderUri(asset.relative_path, nasConfig, pathMode) ?? "#"}
423	                    onClick={(e) => {
424	                      if (!getOpenFolderUri(asset.relative_path, nasConfig, pathMode)) {
425	                        e.preventDefault();
426	                        toast.error("Cannot open folder", {
427	                          description: pathMode === "synology_drive"
428	                            ? "Set your Synology Drive sync root below (the gear icon)."
429	                            : "NAS config missing.",
430	                        });
431	                      }
432	                    }}
433	                  >
434	                    <FolderOpen className="h-3 w-3" />
435	                    Open Containing Folder
436	                  </a>
437	                </Button>
438	                <Popover>
439	                  <PopoverTrigger asChild>
440	                    <Button variant="outline" size="icon" className="h-7 w-7 shrink-0">
441	                      <Settings2 className="h-3 w-3" />
442	                    </Button>
443	                  </PopoverTrigger>
444	                  <PopoverContent className="w-72 p-3 space-y-3" align="end">
445	                    <p className="text-xs font-medium">Open Folder Settings</p>
446	                    <div className="space-y-1">
447	                      <Label className="text-[10px] uppercase text-muted-foreground tracking-wider">Path mode</Label>
448	                      <Select
449	                        value={pathMode}
450	                        onValueChange={(v) => {
451	                          setPathModeState(v as PathMode);
452	                          setPreferredPathMode(v as PathMode);
453	                        }}
454	                      >
455	                        <SelectTrigger className="h-7 text-xs">
456	                          <SelectValue />
457	                        </SelectTrigger>
458	                        <SelectContent>
459	                          <SelectItem value="unc_host" className="text-xs">Office — UNC hostname</SelectItem>
460	                          <SelectItem value="unc_ip" className="text-xs">Office — UNC IP address</SelectItem>
461	                          <SelectItem value="synology_drive" className="text-xs">Remote — Synology Drive (Mac/PC)</SelectItem>
462	                        </SelectContent>
463	                      </Select>
464	                      <p className="text-[10px] text-muted-foreground">
465	                        {pathMode === "synology_drive"
466	                          ? "For designers working remotely via Synology Drive."
467	                          : "For designers on the office network."}
468	                      </p>
469	                    </div>
470	                    {pathMode === "synology_drive" && (
471	                      <div className="space-y-1">
472	                        <Label className="text-[10px] uppercase text-muted-foreground tracking-wider">Your Synology Drive sync root</Label>
473	                        <Input
474	                          className="h-7 text-xs font-mono"
475	                          value={syncRoot}
476	                          onChange={(e) => setSyncRootState(e.target.value)}
477	                          onBlur={() => setUserSyncRoot(syncRoot)}
478	                          placeholder="/Users/you/Synology Drive"
479	                        />
480	                        <p className="text-[10px] text-muted-foreground">
481	                          The local folder where Synology Drive syncs files. Mac example: <span className="font-mono">/Users/you/Synology Drive</span>
482	                        </p>
483	                      </div>
484	                    )}
485	                    <p className="text-[10px] text-muted-foreground border-t pt-2">
486	                      Requires the <strong>PopDAM Helper</strong> app installed on this computer. Download it from Settings → Install Bundles.
487	                    </p>
488	                  </PopoverContent>
489	                </Popover>
490	              </div>
491	            )}
492	            <CopyButton label="Relative" value={asset.relative_path} />
493	            {paths && (
494	              <>
495	                <CopyButton label="Office UNC (hostname)" value={paths.uncHost}
496	                  folderUri={buildOpenFolderUri(paths.uncHost.substring(0, Math.max(paths.uncHost.lastIndexOf("\\"), paths.uncHost.lastIndexOf("/"))))} />
497	                <CopyButton label="Office UNC (IP)" value={paths.uncIp}
498	                  folderUri={buildOpenFolderUri(paths.uncIp.substring(0, Math.max(paths.uncIp.lastIndexOf("\\"), paths.uncIp.lastIndexOf("/"))))} />
499	                {paths.remote && <CopyButton label="Remote (Synology Drive)" value={paths.remote}
500	                  folderUri={buildOpenFolderUri(paths.remote.substring(0, paths.remote.lastIndexOf("/")))} />}
501	              </>
502	            )}
503	          </section>
504	
505	          <Separator />
506	
507	          {/* Tags */}
508	          <section className="space-y-2.5">
509	            <div className="flex items-center justify-between">
510	              <h4 className="flex items-center gap-1.5 text-xs font-medium uppercase tracking-wider text-muted-foreground">
511	                <Tag className="h-3.5 w-3.5" /> Tags
512	              </h4>
513	              <Button
514	                variant="ghost"
515	                size="sm"
516	                className="h-6 text-[10px]"
517	                onClick={() => setEditingTags(!editingTags)}
518	              >
519	                {editingTags ? "Done" : "Edit"}
520	              </Button>
521	            </div>
522	            <div className="flex flex-wrap gap-1.5">
523	              {asset.tags.length === 0 && (
524	                <span className="text-xs text-muted-foreground/50">No tags</span>
525	              )}
526	              {asset.tags.map((tag) => {
527	                const source = tagSourceMap.get(tag);
528	                const isAi = source === "ai";
529	                return (
530	                  <Badge
531	                    key={tag}
532	                    variant="secondary"
533	                    className={cn(
534	                      "text-xs gap-1",
535	                      isAi ? "bg-tag text-tag-foreground" : "bg-accent text-accent-foreground"
536	                    )}
537	                    title={isAi ? `Added by AI${asset.ai_model ? ` (${asset.ai_model})` : ""}` : "Added manually"}
538	                  >
539	                    {isAi && <Sparkles className="h-2.5 w-2.5 opacity-60" />}
540	                    {tag}
541	                    {editingTags && (
542	                      <button onClick={() => removeTag(tag)} className="ml-0.5 hover:text-destructive">
543	                        <X className="h-2.5 w-2.5" />
544	                      </button>
545	                    )}
546	                  </Badge>
547	                );
548	              })}
549	            </div>
550	            {editingTags && (
551	              <form
552	                onSubmit={(e) => { e.preventDefault(); addTag(); }}
